// HTML nümunəsi:
/*
<div id="canvas">Salam, Rəssam!</div>
<button class="draw-btn">Rənglə</button>
*/

// 1. Element seçimi
const canvasElement = document.getElementById("canvas");
console.log(canvasElement); // <div id="canvas">Salam, Rəssam!</div>

const drawButton = document.querySelector(".draw-btn");
console.log(drawButton); // <button class="draw-btn">Rənglə</button>

// 2. Məzmun dəyişdirmə
canvasElement.textContent = "Yeni rəsm əsəri!";
// nəticə: <div id="canvas">Yeni rəsm əsəri!</div>

canvasElement.innerHTML = "<strong>Yeni rəsm!</strong>";
// nəticə: <div id="canvas"><strong>Yeni rəsm!</strong></div>

// 3. Atribut idarəetmə
canvasElement.setAttribute("style", "color: blue;");
// nəticə: <div id="canvas" style="color: blue;"><strong>Yeni rəsm!</strong></div>

console.log(canvasElement.getAttribute("id")); // "canvas"

// 4. Hadisə dinləyicisi
drawButton.addEventListener("click", () => {
  canvasElement.style.backgroundColor = "yellow";
  canvasElement.textContent = "Rəsm rəngləndi!";
});
// nəticə: Düyməyə klikləyəndə div-in fon rəngi sarıya çevrilir

// 5. Yeni element yaratma
const newShape = document.createElement("div");
newShape.textContent = "Yeni forma";
newShape.setAttribute("class", "shape");
document.body.appendChild(newShape);
// nəticə: Səhifəyə yeni <div class="shape">Yeni forma</div> əlavə olunur

// Təhlükə nümunəsi: Təhlükəsiz olmayan innerHTML
const userInput = "<script>alert('Hücum!');</script>";
canvasElement.innerHTML = userInput;
// Təhlükə: Zərərli kod işləyə bilər!

// Təhlükəsiz alternativ
canvasElement.textContent = userInput;
// nəticə: Skript işləməyəcək, sadəcə mətn kimi görünəcək

// Performans nümunəsi: Səmərəli manipulyasiya
const fragment = document.createDocumentFragment();
for (let i = 0; i < 3; i++) {
  const shape = document.createElement("div");
  shape.textContent = `Forma ${i + 1}`;
  fragment.appendChild(shape);
}
document.body.appendChild(fragment);
// nəticə: 3 yeni div bir dəfəyə əlavə olunur, performans yaxşılaşır

// Hadisə ilə dinamik dəyişiklik
const colorInput = document.createElement("input");
colorInput.type = "color";
document.body.appendChild(colorInput);
colorInput.addEventListener("input", () => {
  canvasElement.style.backgroundColor = colorInput.value;
});
// nəticə: Rəng seçdikcə div-in fon rəngi dəyişir

