// HTML example:
/*
<div id="canvas">Hello, Painter!</div>
<button class="draw-btn">Paint</button>
*/

// 1. Selecting elements
const canvasElement = document.getElementById("canvas");
console.log(canvasElement); // <div id="canvas">Hello, Painter!</div>

const drawButton = document.querySelector(".draw-btn");
console.log(drawButton); // <button class="draw-btn">Paint</button>

// 2. Modifying content
canvasElement.textContent = "New artwork!";
// Output: <div id="canvas">New artwork!</div>

canvasElement.innerHTML = "<strong>New painting!</strong>";
// Output: <div id="canvas"><strong>New painting!</strong></div>

// 3. Managing attributes
canvasElement.setAttribute("style", "color: blue;");
// Output: <div id="canvas" style="color: blue;"><strong>New painting!</strong></div>

console.log(canvasElement.getAttribute("id")); // "canvas"

// 4. Event listener
drawButton.addEventListener("click", () => {
  canvasElement.style.backgroundColor = "yellow";
  canvasElement.textContent = "Canvas painted!";
});
// Output: Clicking the button changes the div’s background to yellow

// 5. Creating new elements
const newShape = document.createElement("div");
newShape.textContent = "New shape";
newShape.setAttribute("class", "shape");
document.body.appendChild(newShape);
// Output: Adds <div class="shape">New shape</div> to the page

// Danger example: Unsafe innerHTML
const userInput = "<script>alert('Attack!');</script>";
canvasElement.innerHTML = userInput;
// Danger: Malicious code could run!

// Safe alternative
canvasElement.textContent = userInput;
// Output: Script won’t run, displayed as plain text

// Performance example: Efficient manipulation
const fragment = document.createDocumentFragment();
for (let i = 0; i < 3; i++) {
  const shape = document.createElement("div");
  shape.textContent = `Shape ${i + 1}`;
  fragment.appendChild(shape);
}
document.body.appendChild(fragment);
// Output: Adds 3 new divs at once, improving performance

// Dynamic change with events
const colorInput = document.createElement("input");
colorInput.type = "color";
document.body.appendChild(colorInput);
colorInput.addEventListener("input", () => {
  canvasElement.style.backgroundColor = colorInput.value;
});
// Output: Changing the color input updates the div’s background

