// Пример HTML:
/*
<div id="canvas">Привет, Художник!</div>
<button class="draw-btn">Раскрасить</button>
*/

// 1. Выбор элементов
const canvasElement = document.getElementById("canvas");
console.log(canvasElement); // <div id="canvas">Привет, Художник!</div>

const drawButton = document.querySelector(".draw-btn");
console.log(drawButton); // <button class="draw-btn">Раскрасить</button>

// 2. Изменение содержимого
canvasElement.textContent = "Новое произведение!";
// Вывод: <div id="canvas">Новое произведение!</div>

canvasElement.innerHTML = "<strong>Новая картина!</strong>";
// Вывод: <div id="canvas"><strong>Новая картина!</strong></div>

// 3. Управление атрибутами
canvasElement.setAttribute("style", "color: blue;");
// Вывод: <div id="canvas" style="color: blue;"><strong>Новая картина!</strong></div>

console.log(canvasElement.getAttribute("id")); // "canvas"

// 4. Слушатель событий
drawButton.addEventListener("click", () => {
  canvasElement.style.backgroundColor = "yellow";
  canvasElement.textContent = "Холст раскрашен!";
});
// Вывод: При клике на кнопку фон div становится жёлтым

// 5. Создание новых элементов
const newShape = document.createElement("div");
newShape.textContent = "Новая форма";
newShape.setAttribute("class", "shape");
document.body.appendChild(newShape);
// Вывод: Добавляет <div class="shape">Новая форма</div> на страницу

// Пример опасности: Небезопасный innerHTML
const userInput = "<script>alert('Атака!');</script>";
canvasElement.innerHTML = userInput;
// Опасность: Вредоносный код может выполниться!

// Безопасная альтернатива
canvasElement.textContent = userInput;
// Вывод: Скрипт не выполнится, отобразится как текст

// Пример производительности: Эффективная манипуляция
const fragment = document.createDocumentFragment();
for (let i = 0; i < 3; i++) {
  const shape = document.createElement("div");
  shape.textContent = `Форма ${i + 1}`;
  fragment.appendChild(shape);
}
document.body.appendChild(fragment);
// Вывод: Добавляет 3 новых div за один раз, улучшая производительность

// Динамическое изменение с событиями
const colorInput = document.createElement("input");
colorInput.type = "color";
document.body.appendChild(colorInput);
colorInput.addEventListener("input", () => {
  canvasElement.style.backgroundColor = colorInput.value;
});
// Вывод: Выбор цвета изменяет фон div

